/// <summary>
///    The contract class for the agreement fulfillment report.
/// </summary>
[
    DataContractAttribute
  //  SysOperationGroupAttribute('PrintOptions', "@SYS24353", "2")
]
public class ETG_AgreementConfirmationRDPContract
{
    ModuleSalesPurch                    moduleSalesPurch;
    PurchAgreementId                    purchAgreementId;
    SalesAgreementId                    salesAgreementId;
    RefRecId                            salesAgreementHeaderHistory;
    RefRecId                            purchAgreementHeaderHistory;
    NoYesId                             profoma;

}

Method.Source:
[DataMemberAttribute('ModuleSalesPurch')]
public ModuleSalesPurch parmModuleSalesPurch(ModuleSalesPurch _moduleSalesPurch = moduleSalesPurch)
{
    moduleSalesPurch = _moduleSalesPurch;
    return moduleSalesPurch;
}

[DataMemberAttribute('Agreement history')]
public PurchAgreementId parmPurchAgreementId(PurchAgreementId _purchAgreementId = purchAgreementId)
{
    purchAgreementId = _purchAgreementId;
    return purchAgreementId;
}

[DataMemberAttribute('Sales agreement')]
public SalesAgreementId parmSalesAgreementId(SalesAgreementId _salesAgreementId = salesAgreementId)
{
    salesAgreementId = _salesAgreementId;
    return salesAgreementId;
}

[DataMemberAttribute('Purchase agreement history')]
public RefRecId parmPurchHeaderHistory(RefRecId _purchAgreementHeaderHistory = purchAgreementHeaderHistory)
{
    purchAgreementHeaderHistory = _purchAgreementHeaderHistory;
    return purchAgreementHeaderHistory;
}

[DataMemberAttribute('Sales agreement history')]
public RefRecId parmSalesHeaderHistory(RefRecId _salesAgreementHeaderHistory = salesAgreementHeaderHistory)
{
    salesAgreementHeaderHistory = _salesAgreementHeaderHistory;
    return salesAgreementHeaderHistory;
}

[DataMemberAttribute('Is profoma')]
public NoYesId parmProfoma(NoYesId _profoma = profoma)
{
    profoma = _profoma;
    return profoma;
}
